WITH src AS (SELECT s.slot_name, s.plugin, s.slot_type, s.datoid, s.database, s.temporary, s.active, s.active_pid, s.xmin, s.catalog_xmin, s.restart_lsn, s.confirmed_flush_lsn FROM pg_replication_slots AS s) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.slot_name, src.plugin, src.slot_type, src.datoid, src.database, src.temporary, src.active, src.active_pid, src.xmin, src.catalog_xmin, src.restart_lsn, src.confirmed_flush_lsn, ' ' AS wal_status, ' ' AS safe_wal_size, ' ' AS two_phase FROM src